class Student:
    def __init__(self, name, age):
        self.name = name
        self.age = age
    def introduce(self):
        print(f"大家好，我叫{self.name}，今年{self.age}岁。")
stu1 = Student("张三", 18)
stu2 = Student("李四", 20)
stu1.introduce()
stu2.introduce()

class Account:
    def __init__(self, username, balance):
        self.username = username
        self.__balance = balance
    def get_balance(self):
        return self.__balance
    def deposit(self, amount):
        if amount <= 0:
            print("充值金额必须大于 0")
            return
        self.__balance += amount
        print(f"{self.username} 充值 {amount} 元成功，当前余额：{self.__balance} 元")
account = Account("张三", 100)
print("充值前余额：", account.get_balance())
account.deposit(50)
print("充值后余额：", account.get_balance())

class SweetPotato:
    def __init__(self):
        self.cook_time = 0
        self.cook_state = "生的"
        self.condiments = []
    def cook(self, time):
        self.cook_time += time
        if 0 <= self.cook_time < 3:
            self.cook_state = "生的"
        elif 3 <= self.cook_time < 7:
            self.cook_state = "半生不熟"
        elif 7 <= self.cook_time <= 12:
            self.cook_state = "熟了"
        else:
            self.cook_state = "糊了"
    def add_condiment(self, name):
        self.condiments.append(name)
    def reset(self):
        self.cook_time = 0
        self.cook_state = "生的"
        self.condiments = []
    def __str__(self):
        return f"烤制时间：{self.cook_time}分钟，状态：{self.cook_state}，调料：{self.condiments}"
potato = SweetPotato()
potato.cook(5)
potato.add_condiment("辣椒面")
print(potato)
potato.reset()
print("重置后：", potato)

class ScoreStudent:
    def __init__(self, name, score):
        self.name = name
        self.__score = 0
        self.set_score(score)
    def set_score(self, score):
        if 0 <= score <= 100:
            self.__score = score
        else:
            print("分数必须在 0-100 之间，本次修改无效")
    def get_score(self):
        return self.__score
    def is_pass(self):
        return self.__score >= 60
    def __str__(self):
        result = "及格" if self.is_pass() else "不及格"
        return f"学生：{self.name}，分数：{self.__score}，结果：{result}"
stu1 = ScoreStudent("张三", 88)
stu2 = ScoreStudent("李四", 50)
print(stu1)
print(stu2)
stu1.set_score(150)
print(stu1)
stu2.set_score(70)
print(stu2)
